CREATE TRIGGER tr_total_loans AFTER UPDATE OF status ON loan FOR EACH ROW BEGIN
    INSERT OR IGNORE INTO loan_summary (account_id) VALUES (NEW.account_id);
    UPDATE loan_summary SET total_loan_count = (SELECT COUNT(*) FROM loan WHERE account_id = NEW.account_id AND status = 'A') WHERE account_id = NEW.account_id;
END

WITH RECURSIVE curricula_to_upgrade AS (
  SELECT curriculum_id FROM curricula WHERE curriculum_id = 1 AND status = 'installed'
  UNION ALL
  SELECT cr.curriculum_id FROM curriculum_resources cr JOIN curricula_to_upgrade ctu ON cr.resource_key = ctu.curriculum_id
) SELECT curriculum_id FROM curricula_to_upgrade;
UPDATE curricula SET status = 'to upgrade' WHERE curriculum_id IN (SELECT curriculum_id FROM curricula WHERE curriculum_id = 1)

