BEGIN TRANSACTION;

 CREATE TEMPORARY TABLE temp_updated_events AS
 SELECT event_id
 FROM event
 WHERE status <> 'Closed' AND status <> 'Processing'
 ORDER BY event_date
 LIMIT 5;

 UPDATE event
 SET status = 'Processing'
 WHERE event_id IN (SELECT event_id FROM temp_updated_events);

 SELECT * FROM event
 WHERE event_id IN (SELECT event_id FROM temp_updated_events);

 DROP TABLE temp_updated_events;

 COMMIT

DROP TABLE IF EXISTS "EventCategories";
CREATE TABLE "EventCategories" ("ID" INTEGER PRIMARY KEY AUTOINCREMENT, "IsBusinessCategory" INTEGER NULL);
DROP TABLE IF EXISTS "BusinessCategories";
CREATE TABLE "BusinessCategories" ("ID" INTEGER PRIMARY KEY AUTOINCREMENT, "BusinessCategoryID" INTEGER NOT NULL REFERENCES "EventCategories" ("ID"));
CREATE TRIGGER check_business_category
BEFORE INSERT OR UPDATE ON BusinessCategories
FOR EACH ROW
BEGIN
    SELECT CASE
        WHEN NEW.BusinessCategoryID IS NOT NULL AND 
             (SELECT IsBusinessCategory FROM EventCategories WHERE ID = NEW.BusinessCategoryID) IS NOT 1
        THEN RAISE(ABORT, 'BusinessCategoryID must reference an EventCategories with IsBusinessCategory = 1')
    END;
END

